const ORIG={};
document.querySelectorAll('[data-i18n]').forEach(el=>{ORIG[el.getAttribute('data-i18n')]=el.innerHTML;});

function setHeaderHeightVar(){
  const hdr = document.querySelector('.hdr');
  if(hdr) document.documentElement.style.setProperty('--header-h', hdr.offsetHeight + 'px');
}
setHeaderHeightVar();
window.addEventListener('resize', setHeaderHeightVar);
window.addEventListener('load', setHeaderHeightVar);
if(document.fonts && document.fonts.ready){ document.fonts.ready.then(setHeaderHeightVar); }

function applyNavMode(l){
  // JA = vertical sidebar. VI / EN = horizontal top bar.
  document.body.classList.toggle('nav-vertical', l==='ja');
  document.body.classList.toggle('nav-horizontal', l!=='ja');
  setTimeout(setHeaderHeightVar, 0);
}

