  "services.html": {ja:"事業内容｜株式会社NASON HOME", vi:"Dịch vụ｜Công ty Cổ phần NASON HOME", en:"Our Services｜NASON HOME Co., Ltd."},
  "areas.html": {ja:"対応エリア｜株式会社NASON HOME", vi:"Khu vực phục vụ｜Công ty Cổ phần NASON HOME", en:"Areas We Serve｜NASON HOME Co., Ltd."},
  "voice.html": {ja:"入居者の声｜株式会社NASON HOME", vi:"Đánh giá khách hàng｜Công ty Cổ phần NASON HOME", en:"Customer Testimonials｜NASON HOME Co., Ltd."},
