function applyPageTitle(l){
  const path = location.pathname.split('/').pop() || 'index.html';
  const t = PAGE_TITLES[path];
  if(t) document.title = t[l] || t.ja;
}

function setLang(l){
  document.querySelectorAll('[data-i18n]').forEach(el=>{
    const k=el.getAttribute('data-i18n');
    const v=(l==='ja')?ORIG[k]:(I18N[l]&&I18N[l][k]);
    if(v!==undefined) el.innerHTML=v;
  });
  document.documentElement.lang=l;
  document.querySelectorAll('.lang button').forEach(b=>b.classList.toggle('on',b.dataset.l===l));
  applyNavMode(l);
  applyPageTitle(l);
  try{ localStorage.setItem('nason_lang', l); }catch(e){}
}
document.querySelectorAll('.lang button').forEach(b=>b.addEventListener('click',()=>setLang(b.dataset.l)));

// Restore language choice across page navigations (real multi-page site now)
(function initLang(){
  let saved = null;
  try{ saved = localStorage.getItem('nason_lang'); }catch(e){}
  if(saved && saved !== 'ja'){ setLang(saved); } else { applyNavMode('ja'); }
})();

/* horizontal dropdowns (VI/EN top bar: 会社情報 / 事業内容) */
document.querySelectorAll('.drop').forEach(d=>{
  const btn=d.querySelector('button');
  btn.addEventListener('click',e=>{e.stopPropagation();document.querySelectorAll('.drop').forEach(x=>x!==d&&x.classList.remove('open'));d.classList.toggle('open');});
});
document.addEventListener('click',()=>document.querySelectorAll('.drop').forEach(d=>d.classList.remove('open')));

/* sidebar accordions (JA vertical mode) */
document.querySelectorAll('.side-acc>button').forEach(b=>b.addEventListener('click',()=>b.parentElement.classList.toggle('open')));

/* mobile menu + accordions (all languages, narrow viewport) */
const burgerEl = document.getElementById('burger');
if(burgerEl) burgerEl.addEventListener('click',()=>document.getElementById('mmenu').classList.toggle('show'));
document.querySelectorAll('.m-acc>button').forEach(b=>b.addEventListener('click',()=>b.parentElement.classList.toggle('open')));

/* reveal on scroll */
const io=new IntersectionObserver((es)=>es.forEach(e=>{if(e.isIntersecting){e.target.classList.add('in');io.unobserve(e.target);}}),{threshold:.1});
document.querySelectorAll('.rv').forEach(el=>io.observe(el));

/* contact form — sends via the /api/contact serverless function (only present on contact.html) */
const contactForm = document.getElementById('contactForm');
if(contactForm){
  const EMAIL_RE = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  const FORM_MSG = {
    ja:{ sending:'送信中…', error:'送信に失敗しました。時間をおいて再度お試しください。', invalid:'必須項目（お名前・メールアドレス・お問い合わせ内容・同意）をご確認ください。' },
    vi:{ sending:'Đang gửi…', error:'Gửi không thành công. Vui lòng thử lại sau.', invalid:'Vui lòng kiểm tra các mục bắt buộc (họ tên, email, nội dung, đồng ý).' },
    en:{ sending:'Sending…', error:'Failed to send. Please try again later.', invalid:'Please check the required fields (name, email, message, consent).' }
  };
  const msg = (k)=> (FORM_MSG[document.documentElement.lang]||FORM_MSG.ja)[k];
  const errorBox = document.getElementById('formError');
  const submitBtn = contactForm.querySelector('button[type="submit"]');

  const showError = (text)=>{ if(errorBox){ errorBox.textContent = text; errorBox.hidden = false; } };
  const clearError = ()=>{ if(errorBox){ errorBox.hidden = true; errorBox.textContent=''; } };

  contactForm.addEventListener('submit', async function(e){
    e.preventDefault();
    clearError();

    const f = this.elements;
    const payload = {
      name:(f.name.value||'').trim(),
      email:(f.email.value||'').trim(),
      phone:(f.phone.value||'').trim(),
      type:f.type.value,
      language:f.language.value,
      message:(f.message.value||'').trim(),
      privacy:f.privacy.checked
    };

    // Client-side validation (mirrors the server; never the only check).
    if(!payload.name || !EMAIL_RE.test(payload.email) || !payload.message || !payload.privacy){
      showError(msg('invalid'));
      return;
    }

    const originalLabel = submitBtn.textContent;
    submitBtn.disabled = true;
    submitBtn.textContent = msg('sending');

    try{
      const res = await fetch('/api/contact', {
        method:'POST',
        headers:{ 'Content-Type':'application/json' },
        body:JSON.stringify(payload)
      });
      if(!res.ok) throw new Error('Request failed: '+res.status);

      // Success — reset input and reveal the thank-you panel.
      this.reset();
      this.style.display='none';
      document.getElementById('formSuccess').classList.add('show');
    }catch(err){
      // Failure — keep the user's input, re-enable the button, show the error.
      showError(msg('error'));
      submitBtn.disabled = false;
      submitBtn.textContent = originalLabel;
    }
  });
}
